/* eslint-disable @next/next/no-img-element */
"use client";

import { useEffect, useRef, useState } from "react";

type Status = "idle" | "connecting" | "active" | "error";

type TranscriptItem = {
  id: string;
  role: "user" | "assistant";
  text: string;
  interrupted?: boolean;
};

const voiceOptions = ["Eve", "Ara", "Leo", "Rex", "Sal"] as const;

export function VoiceLab() {
  const [status, setStatus] = useState<Status>("idle");
  const [voice, setVoice] = useState<(typeof voiceOptions)[number]>("Eve");
  const [instructions, setInstructions] = useState(
    "Eres un agente de soporte amable. Responde breve.",
  );
  const [error, setError] = useState<string | null>(null);
  const [transcript, setTranscript] = useState<TranscriptItem[]>([]);
  const [vadThreshold, setVadThreshold] = useState(0.85);
  const [silenceMs, setSilenceMs] = useState(200);
  const [tokenExpiresAt, setTokenExpiresAt] = useState<number | null>(null);

  const wsRef = useRef<WebSocket | null>(null);
  const sourceNodeRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const micStreamRef = useRef<MediaStream | null>(null);
  const workletNodeRef = useRef<AudioWorkletNode | null>(null);
  const micBufferRef = useRef<Int16Array[]>([]);
  const isSessionReadyRef = useRef(false);
  const nextPlayTimeRef = useRef(0);
  const playbackSourcesRef = useRef<AudioBufferSourceNode[]>([]);
  const currentResponseIdRef = useRef<string | null>(null);
  const tokenTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const intentionalDisconnectRef = useRef(false);
  const connectionTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Helpers
  const clearTokenTimer = () => {
    if (tokenTimerRef.current) {
      clearTimeout(tokenTimerRef.current);
      tokenTimerRef.current = null;
    }
  };

  const scheduleRefresh = (expiresAt: number) => {
    clearTokenTimer();
    const now = Date.now() / 1000;
    const seconds = Math.max(expiresAt - now - 5, 5);
    tokenTimerRef.current = setTimeout(() => {
      void fetchToken();
    }, seconds * 1000);
  };

  const clearConnectionTimeout = () => {
    if (connectionTimeoutRef.current) {
      clearTimeout(connectionTimeoutRef.current);
      connectionTimeoutRef.current = null;
    }
  };

  const fetchToken = async () => {
    try {
      const res = await fetch("/api/xai/realtime/token", { method: "POST" });
      const data = await res.json();
      if (!res.ok) {
        throw new Error(data?.error || "No se pudo crear token");
      }
      setTokenExpiresAt(data.expiresAt ?? null);
      if (data.expiresAt) scheduleRefresh(data.expiresAt);
      return data.token as string;
    } catch (err) {
      setError("No se pudo obtener token de sesion.");
      setStatus("error");
      console.error(err);
      return null;
    }
  };

  const audioToBase64 = (int16: Int16Array) => {
    const bytes = new Uint8Array(
      int16.buffer,
      int16.byteOffset,
      int16.byteLength,
    );
    const CHUNK = 0x2000;
    const parts: string[] = [];
    for (let i = 0; i < bytes.length; i += CHUNK) {
      parts.push(
        String.fromCharCode.apply(
          null,
          Array.from(bytes.subarray(i, i + CHUNK)),
        ),
      );
    }
    return btoa(parts.join(""));
  };

  const interruptPlayback = () => {
    playbackSourcesRef.current.forEach((src) => {
      try {
        src.stop();
      } catch {
        /* ignore */
      }
    });
    playbackSourcesRef.current = [];
    nextPlayTimeRef.current = 0;
  };

  const playPcmChunk = (base64: string) => {
    const audioCtx = audioCtxRef.current;
    if (!audioCtx) return;
    const raw = atob(base64);
    const bytes = new Uint8Array(raw.length);
    for (let i = 0; i < raw.length; i++) bytes[i] = raw.charCodeAt(i);
    const int16 = new Int16Array(bytes.buffer);
    const float32 = new Float32Array(int16.length);
    for (let i = 0; i < int16.length; i++) float32[i] = int16[i] / 32768;

    const buf = audioCtx.createBuffer(1, float32.length, 24000);
    buf.getChannelData(0).set(float32);
    const src = audioCtx.createBufferSource();
    src.buffer = buf;
    src.connect(audioCtx.destination);

    const now = audioCtx.currentTime;
    const startAt = Math.max(now, nextPlayTimeRef.current);
    src.start(startAt);
    nextPlayTimeRef.current = startAt + buf.duration;
    playbackSourcesRef.current.push(src);
    src.onended = () => {
      playbackSourcesRef.current = playbackSourcesRef.current.filter(
        (s) => s !== src,
      );
    };
  };

  const stopAll = (nextStatus: Status = "idle") => {
    clearTokenTimer();
    clearConnectionTimeout();
    isSessionReadyRef.current = false;
    micBufferRef.current = [];
    currentResponseIdRef.current = null;
    intentionalDisconnectRef.current = true;
    try {
      wsRef.current?.close();
    } catch {
      /* noop */
    }
    wsRef.current = null;
    interruptPlayback();
    if (sourceNodeRef.current) {
      try {
        sourceNodeRef.current.disconnect();
      } catch {
        /* noop */
      }
      sourceNodeRef.current = null;
    }
    if (workletNodeRef.current) {
      try {
        workletNodeRef.current.port.close();
        workletNodeRef.current.disconnect();
      } catch {
        /* noop */
      }
      workletNodeRef.current = null;
    }
    if (micStreamRef.current) {
      micStreamRef.current.getTracks().forEach((t) => t.stop());
      micStreamRef.current = null;
    }
    if (audioCtxRef.current) {
      audioCtxRef.current.close().catch(() => undefined);
      audioCtxRef.current = null;
    }
    setStatus(nextStatus);
  };

  useEffect(() => {
    return () => stopAll();
  }, []);

  const start = async () => {
    setError(null);
    setStatus("connecting");
    intentionalDisconnectRef.current = false;

    try {
      const audioCtx = new AudioContext({ sampleRate: 24000 });
      if (audioCtx.state === "suspended") await audioCtx.resume();
      audioCtxRef.current = audioCtx;
    } catch (err) {
      console.error(err);
      setError("No se pudo preparar el audio del navegador.");
      setStatus("error");
      return;
    }

    const token = await fetchToken();
    if (!token) {
      stopAll("error");
      return;
    }

    const audioCtx = audioCtxRef.current;
    if (!audioCtx) {
      setStatus("error");
      return;
    }

    // Mic + AudioContext in parallel
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: {
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true,
          sampleRate: 24000,
        },
      });
      micStreamRef.current = stream;
      await audioCtx.audioWorklet.addModule("/pcm-processor-worklet.js");
      const source = audioCtx.createMediaStreamSource(stream);
      sourceNodeRef.current = source;
      const worklet = new AudioWorkletNode(audioCtx, "pcm-processor");
      workletNodeRef.current = worklet;

      worklet.port.onmessage = (event) => {
        const int16 = event.data as Int16Array;
        if (isSessionReadyRef.current && wsRef.current?.readyState === 1) {
          wsRef.current.send(
            JSON.stringify({
              type: "input_audio_buffer.append",
              audio: audioToBase64(int16),
            }),
          );
        } else {
          // buffer while waiting for session.updated
          if (micBufferRef.current.length < 120) {
            micBufferRef.current.push(int16);
          }
        }
      };

      source.connect(worklet);
    } catch (err) {
      console.error(err);
      setError("No se pudo acceder al microfono.");
      setStatus("error");
      return;
    }

    const ws = new WebSocket("wss://api.x.ai/v1/realtime", [
      `xai-client-secret.${token}`,
    ]);
    wsRef.current = ws;
    connectionTimeoutRef.current = setTimeout(() => {
      if (ws.readyState !== WebSocket.OPEN) {
        setError("Timeout conectando con xAI Realtime.");
        stopAll("error");
      }
    }, 10000);

    ws.onopen = () => {
      clearConnectionTimeout();
      const sessionUpdate = {
        type: "session.update",
        session: {
          voice,
          instructions,
          turn_detection: {
            type: "server_vad",
            threshold: vadThreshold,
            silence_duration_ms: silenceMs,
          },
          input_audio_transcription: { model: "grok-2-audio" },
          audio: {
            input: { format: { type: "audio/pcm", rate: 24000 } },
            output: { format: { type: "audio/pcm", rate: 24000 } },
          },
        },
      };
      ws.send(JSON.stringify(sessionUpdate));
    };

    ws.onerror = () => {
      setError("WebSocket error");
      stopAll("error");
    };

    ws.onclose = () => {
      clearConnectionTimeout();
      if (!intentionalDisconnectRef.current) {
        setStatus("idle");
      }
    };

    ws.onmessage = ({ data }) => {
      const event = JSON.parse(data);
      switch (event.type) {
        case "session.updated": {
          isSessionReadyRef.current = true;
          setStatus("active");
          const buffered = micBufferRef.current;
          micBufferRef.current = [];
          buffered.forEach((chunk) => {
            ws.send(
              JSON.stringify({
                type: "input_audio_buffer.append",
                audio: audioToBase64(chunk),
              }),
            );
          });
          break;
        }
        case "input_audio_buffer.speech_started": {
          interruptPlayback();
          ws.send(JSON.stringify({ type: "response.cancel" }));
          if (currentResponseIdRef.current) {
            setTranscript((prev) =>
              prev.map((m) =>
                m.id === currentResponseIdRef.current
                  ? { ...m, interrupted: true }
                  : m,
              ),
            );
          }
          currentResponseIdRef.current = null;
          break;
        }
        case "conversation.item.input_audio_transcription.completed": {
          const text = event.transcript as string;
          setTranscript((prev) => [
            ...prev,
            { id: event.item?.id ?? crypto.randomUUID(), role: "user", text },
          ]);
          break;
        }
        case "response.created": {
          currentResponseIdRef.current = event.response?.id;
          setTranscript((prev) => [
            ...prev,
            {
              id: event.response?.id ?? crypto.randomUUID(),
              role: "assistant",
              text: "",
            },
          ]);
          break;
        }
        case "response.output_audio_transcript.delta": {
          const delta = event.delta as string;
          const rid = currentResponseIdRef.current;
          if (!rid) break;
          setTranscript((prev) =>
            prev.map((m) =>
              m.id === rid ? { ...m, text: m.text + delta } : m,
            ),
          );
          break;
        }
        case "response.output_audio.delta": {
          const base64 = event.delta as string;
          playPcmChunk(base64);
          break;
        }
        case "response.done": {
          currentResponseIdRef.current = null;
          break;
        }
        case "error": {
          setError(event.message || "Error en la sesion");
          stopAll("error");
          break;
        }
      }
    };
  };

  const toggle = () => {
    if (status === "idle" || status === "error") {
      start();
    } else {
      stopAll();
    }
  };

  return (
    <section className="py-14 px-6 bg-gradient-to-br from-slate-950 via-slate-900 to-slate-800 text-white">
      <div className="max-w-6xl mx-auto grid gap-8 lg:grid-cols-[1.1fr_0.9fr] items-start">
        <div className="space-y-3">
          <p className="text-sm uppercase tracking-[0.2em] text-lime-400">
            Voz en tiempo real
          </p>
          <h2 className="text-3xl font-semibold">Agente de voz con Grok</h2>
          <p className="text-gray-200">
            Conecta micrÃ³fono y altavoces del navegador. Usamos token efÃ­mero,
            VAD del servidor y transcripciÃ³n en vivo. No exponemos tu API key.
          </p>
          <div className="grid gap-3 rounded-xl border border-slate-800 bg-black/40 p-4">
            <label className="flex items-center justify-between gap-3 text-sm">
              <span>Voz</span>
              <select
                value={voice}
                onChange={(e) =>
                  setVoice(e.target.value as (typeof voiceOptions)[number])
                }
                className="rounded-lg bg-slate-900 border border-slate-700 px-3 py-2 text-white"
              >
                {voiceOptions.map((v) => (
                  <option key={v}>{v}</option>
                ))}
              </select>
            </label>
            <label className="flex flex-col gap-2 text-sm">
              <span>Instrucciones</span>
              <textarea
                value={instructions}
                onChange={(e) => setInstructions(e.target.value)}
                className="rounded-lg bg-slate-900 border border-slate-700 px-3 py-2 text-white"
                rows={3}
                suppressHydrationWarning
              />
            </label>
            <div className="grid grid-cols-2 gap-3 text-sm">
              <label className="flex flex-col gap-1">
                <span>VAD threshold</span>
                <input
                  type="range"
                  min={0.1}
                  max={1}
                  step={0.05}
                  value={vadThreshold}
                  onChange={(e) => setVadThreshold(parseFloat(e.target.value))}
                />
                <span className="text-xs text-gray-400">
                  {vadThreshold.toFixed(2)}
                </span>
              </label>
              <label className="flex flex-col gap-1">
                <span>Silencio (ms)</span>
                <input
                  type="range"
                  min={0}
                  max={1500}
                  step={50}
                  value={silenceMs}
                  onChange={(e) => setSilenceMs(parseInt(e.target.value, 10))}
                />
                <span className="text-xs text-gray-400">{silenceMs} ms</span>
              </label>
            </div>
            <p className="text-xs text-gray-500">
              Estado: {status}
              {tokenExpiresAt
                ? ` · token expira en ${Math.max(
                    0,
                    Math.floor(tokenExpiresAt - Date.now() / 1000),
                  )}s`
                : ""}
            </p>
            {error && <p className="text-sm text-red-400">{error}</p>}
          </div>
          <p className="text-xs text-gray-400">
            Recomendado para 1:1 en navegador. Si necesitas multiusuario o SIP,
            migra a LiveKit y reusa el backend de tokens.
          </p>
        </div>

        <div className="rounded-2xl border border-slate-800 bg-black/60 p-6 shadow-xl space-y-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <span
                className={`h-2 w-2 rounded-full ${
                  status === "active"
                    ? "bg-lime-400"
                    : status === "connecting"
                      ? "bg-amber-400"
                      : status === "error"
                        ? "bg-red-400"
                        : "bg-slate-500"
                }`}
              />
              <p className="text-sm text-gray-200 capitalize">{status}</p>
            </div>
            <button
              type="button"
              onClick={toggle}
              className={`rounded-full px-5 py-2 text-sm font-semibold shadow transition ${
                status === "idle" || status === "error"
                  ? "bg-lime-400 text-black hover:bg-lime-300"
                  : "bg-red-500 text-white hover:bg-red-400"
              }`}
            >
              {status === "idle" || status === "error" ? "Conectar" : "Detener"}
            </button>
          </div>

          <div className="space-y-3 max-h-[360px] overflow-y-auto pr-1">
            {transcript.length === 0 && (
              <p className="text-sm text-gray-500">
                AÃºn no hay mensajes. Pulsa conectar y habla.
              </p>
            )}
            {transcript.map((item) => (
              <div
                key={item.id}
                className="flex gap-3 rounded-xl border border-slate-800 bg-slate-900/60 p-3"
              >
                <div className="mt-1 h-8 w-8 rounded-full bg-slate-800 flex items-center justify-center text-xs uppercase">
                  {item.role === "user" ? "TÃº" : "AI"}
                </div>
                <div className="text-sm text-gray-100">
                  <p className={item.interrupted ? "opacity-60" : ""}>
                    {item.text || "…"}
                  </p>
                  {item.interrupted && (
                    <span className="text-xs text-orange-400">
                      (interrumpido)
                    </span>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
